package main

import (
	"fmt"
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Text   template.HTML // To allow for basic formatting like bold, italics etc.
}

var comments = []Comment{
	{"User1", "This is <b>bold</b> comment."},
	// more users and their comments can go here...
}

func main() {
	http.HandleFunc("/comments", CommentsHandler)
	fmt.Println("Listening on port 8080")
	http.ListenAndServe(":8080", nil)
}

func CommentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.New("comments").Parse(commentTemplate))
	err := tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

var commentTemplate = `
<!DOCTYPE html>
<html>
  <head>
    <title>Comments</title>
  </head>
  <body>
    {{range .}}
      <h3>{{.Author}}:</h3>
      <p>{{.Text}}</p>
    {{end}}
  </body>
</html>`